class Solution:
    def numPoints(self, darts: list, r: int) -> int:
        import math
        n = len(darts)
        if n == 1:
            return 1
        EPS = 1e-6

        def count(cx, cy):
            return sum(1 for x, y in darts if (x - cx)**2 + (y - cy)**2 <= r * r + EPS)

        best = 1
        for i in range(n):
            for j in range(i + 1, n):
                x1, y1 = darts[i]
                x2, y2 = darts[j]
                d = math.dist((x1, y1), (x2, y2))
                if d > 2 * r:
                    continue
                mx, my = (x1 + x2) / 2, (y1 + y2) / 2
                h = math.sqrt(max(0.0, r * r - (d / 2) ** 2))
                dx, dy = (y2 - y1) / d, -(x2 - x1) / d
                for cx, cy in [(mx + h * dx, my + h * dy), (mx - h * dx, my - h * dy)]:
                    best = max(best, count(cx, cy))
        return best

