var numPoints = function(darts, r) {
    const n = darts.length;
    if (n === 1) return 1;
    const EPS = 1e-6;
    function countIn(cx, cy) {
        let c = 0;
        for (const [x, y] of darts) {
            if ((x-cx)**2 + (y-cy)**2 <= r*r + EPS) c++;
        }
        return c;
    }
    let best = 1;
    for (let i = 0; i < n; i++) {
        for (let j = i+1; j < n; j++) {
            const [x1,y1] = darts[i], [x2,y2] = darts[j];
            const d = Math.hypot(x2-x1, y2-y1);
            if (d > 2*r) continue;
            const mx = (x1+x2)/2, my = (y1+y2)/2;
            const h = Math.sqrt(Math.max(0, r*r - (d/2)**2));
            const dx = (y2-y1)/d, dy = -(x2-x1)/d;
            for (const [cx,cy] of [[mx+h*dx,my+h*dy],[mx-h*dx,my-h*dy]]) {
                best = Math.max(best, countIn(cx,cy));
            }
        }
    }
    return best;
};
